#!/bin/bash
# 'cmpe' ile baslayan ama 'cmpe2' ile baslamayan dosyalari listele
for i in *; do
  if [[ $i == cmpe* && $i != cmpe2* ]]; then echo $i;
  fi
done

#include <stdio.h>
int main(int argc, char** argv) {
  int i;
  for (i = 0; i < argc; ++i) {
    printf("argv[%d] = %s\n", i, argv[i]);
  }
  return 0;
}

